  public static abstract class BoolType extends TLObject {
    public static final String TYPE = "Bool";

    public static ApiScheme.BoolType readType(TLInputStream istream, TLContext context) throws Exception {
      int id = istream.readInt();
      istream.skip(-4);
      ApiScheme.BoolType a = null;
      switch (id) {
        case ApiScheme.boolFalse.ID:
          a = new ApiScheme.boolFalse();
          break;
        case ApiScheme.boolTrue.ID:
          a = new ApiScheme.boolTrue();
          break;
        default:
          a = null;

      }
      if (a != null) {
        a.read(istream, context);
      } else {
        throw new TLNotFoundException(id);
      }
      return a;
    }
  }

