  public static class messageActionPaymentSentMe extends ApiScheme.MessageActionType {
    public static final int ID = 0xffa00ccc;
    public static final boolean IS_CONSTRUCTOR = true;
    public static final String NAME = "messageActionPaymentSentMe";
    public int flags;
    public boolean recurring_init;
    public boolean recurring_used;
    public String currency;
    public long total_amount;
    public byte[] payload;
    public ApiScheme.PaymentRequestedInfoType info = null;
    public String shipping_option_id;
    public ApiScheme.PaymentChargeType charge;
    public Integer subscription_until_date;


    @Override
    public int getId() {
      return ID;
    }

    @Override
    public boolean isConstructor() {
      return IS_CONSTRUCTOR;
    }

    @Override
    public String getName() {
      return NAME;
    }

    @Override
    public void readParams(TLInputStream istream, TLContext context) throws Exception {
      flags = istream.readInt32();
      if ((flags & 4) != 0) {
        recurring_init = true;
      }
      if ((flags & 8) != 0) {
        recurring_used = true;
      }
      currency = istream.readTLString();
      total_amount = istream.readInt64();
      payload = istream.readTLBytes();
      if ((flags & 1) != 0) {
        info = ApiScheme.PaymentRequestedInfoType.readType(istream, context);
      }
      if ((flags & 2) != 0) {
        shipping_option_id = istream.readTLString();
      }
      charge = ApiScheme.PaymentChargeType.readType(istream, context);
      if ((flags & 16) != 0) {
        subscription_until_date = istream.readInt32();
      }

    }

    @Override
    public void writeParams(TLOutputStream ostream) throws Exception {
      flags = recurring_init ? (flags | 4) : (flags & ~4);
      flags = recurring_used ? (flags | 8) : (flags & ~8);
      flags = info != null ? (flags | 1) : (flags & ~1);
      flags = shipping_option_id != null ? (flags | 2) : (flags & ~2);
      flags = subscription_until_date != null ? (flags | 16) : (flags & ~16);
      ostream.writeInt32(flags);
      if ((flags & 4) != 0) {

      }
      if ((flags & 8) != 0) {

      }
      ostream.writeTLString(currency);
      ostream.writeInt64(total_amount);
      ostream.writeTLBytes(payload);
      if ((flags & 1) != 0) {
        info.write(ostream);
      }
      if ((flags & 2) != 0) {
        ostream.writeTLString(shipping_option_id);
      }
      charge.write(ostream);
      if ((flags & 16) != 0) {
        ostream.writeInt32(subscription_until_date);
      }

    }

    @Override
    public JsonObject toJSON() {
      Map<String, Object> _json = new LinkedHashMap<>();
      _json.put("@id", getId());
      _json.put("@name", getName());
      _json.put("@type", TYPE);
      _json.put("flags", flags);
      _json.put("recurring_init", recurring_init);
      _json.put("recurring_used", recurring_used);
      _json.put("currency", currency);
      _json.put("total_amount", total_amount);
      _json.put("payload", Base64.getEncoder().encodeToString(payload));
      _json.put("info", info != null ? info.toJSON() : null);
      _json.put("shipping_option_id", shipping_option_id);
      _json.put("charge", charge.toJSON());
      _json.put("subscription_until_date", subscription_until_date);

      return GSON.toJsonTree(_json).getAsJsonObject();
    }

    @Override
    public String toString() {
      return toJSON().toString();
    }
  }


