  public static class document extends ApiScheme.DocumentType {
    public static final int ID = 0x8fd4c4d8;
    public static final boolean IS_CONSTRUCTOR = true;
    public static final String NAME = "document";
    public int flags;
    public long id;
    public long access_hash;
    public byte[] file_reference;
    public int date;
    public String mime_type;
    public long size;
    public TLVector<ApiScheme.PhotoSizeType> thumbs = null;
    public TLVector<ApiScheme.VideoSizeType> video_thumbs = null;
    public int dc_id;
    public TLVector<ApiScheme.DocumentAttributeType> attributes = new TLVector<>(ApiScheme.DocumentAttributeType.class);


    @Override
    public int getId() {
      return ID;
    }

    @Override
    public boolean isConstructor() {
      return IS_CONSTRUCTOR;
    }

    @Override
    public String getName() {
      return NAME;
    }

    @Override
    public void readParams(TLInputStream istream, TLContext context) throws Exception {
      flags = istream.readInt32();
      id = istream.readInt64();
      access_hash = istream.readInt64();
      file_reference = istream.readTLBytes();
      date = istream.readInt32();
      mime_type = istream.readTLString();
      size = istream.readInt64();
      if ((flags & 1) != 0) {
        thumbs = new TLVector<>(ApiScheme.PhotoSizeType.class);
        thumbs.read(istream, context);
      }
      if ((flags & 2) != 0) {
        video_thumbs = new TLVector<>(ApiScheme.VideoSizeType.class);
        video_thumbs.read(istream, context);
      }
      dc_id = istream.readInt32();
      attributes.read(istream, context);

    }

    @Override
    public void writeParams(TLOutputStream ostream) throws Exception {
      flags = thumbs != null ? (flags | 1) : (flags & ~1);
      flags = video_thumbs != null ? (flags | 2) : (flags & ~2);
      ostream.writeInt32(flags);
      ostream.writeInt64(id);
      ostream.writeInt64(access_hash);
      ostream.writeTLBytes(file_reference);
      ostream.writeInt32(date);
      ostream.writeTLString(mime_type);
      ostream.writeInt64(size);
      if ((flags & 1) != 0) {
        thumbs.write(ostream);
      }
      if ((flags & 2) != 0) {
        video_thumbs.write(ostream);
      }
      ostream.writeInt32(dc_id);
      attributes.write(ostream);

    }

    @Override
    public JsonObject toJSON() {
      Map<String, Object> _json = new LinkedHashMap<>();
      _json.put("@id", getId());
      _json.put("@name", getName());
      _json.put("@type", TYPE);
      _json.put("flags", flags);
      _json.put("id", id);
      _json.put("access_hash", access_hash);
      _json.put("file_reference", Base64.getEncoder().encodeToString(file_reference));
      _json.put("date", date);
      _json.put("mime_type", mime_type);
      _json.put("size", size);
      _json.put("thumbs", thumbs != null ? thumbs.toJSON() : null);
      _json.put("video_thumbs", video_thumbs != null ? video_thumbs.toJSON() : null);
      _json.put("dc_id", dc_id);
      _json.put("attributes", attributes.toJSON());

      return GSON.toJsonTree(_json).getAsJsonObject();
    }

    @Override
    public String toString() {
      return toJSON().toString();
    }
  }


