    public static final int ID = 0x4d93a990;
    public static final boolean IS_CONSTRUCTOR = true;
    public static final String NAME = "sponsoredMessage";
    public int flags;
    public boolean recommended;
    public boolean can_report;
    public byte[] random_id;
    public String url;
    public String title;
    public String message;
    public TLVector<ApiScheme.MessageEntityType> entities = null;
    public ApiScheme.PhotoType photo = null;
    public ApiScheme.MessageMediaType media = null;
    public ApiScheme.PeerColorType color = null;
    public String button_text;
    public String sponsor_info;
    public String additional_info;


    @Override
    public int getId() {
      return ID;
    }

