      public static final int ID = 0xf40c0224;
      public static final boolean IS_CONSTRUCTOR = false;
      public static final String NAME = "channels.createForumTopic";
      public static final String RETURN_TYPE = "Updates";
      public int flags;
      public ApiScheme.InputChannelType channel;
      public String title;
      public Integer icon_color;
      public Long icon_emoji_id;
      public long random_id;
      public ApiScheme.InputPeerType send_as = null;


      public createForumTopic() {
        super(ApiScheme.UpdatesType.class);
      }

      @Override
      public int getId() {
        return ID;
      }

      @Override
      public boolean isConstructor() {
        return IS_CONSTRUCTOR;
      }

      @Override
      public String getName() {
        return NAME;
      }

      @Override
      public void readParams(TLInputStream istream, TLContext context) throws Exception {
        flags = istream.readInt32();
        channel = ApiScheme.InputChannelType.readType(istream, context);
        title = istream.readTLString();
        if ((flags & 1) != 0) {
          icon_color = istream.readInt32();
        }
        if ((flags & 8) != 0) {
          icon_emoji_id = istream.readInt64();
        }
        random_id = istream.readInt64();
        if ((flags & 4) != 0) {
          send_as = ApiScheme.InputPeerType.readType(istream, context);
        }

      }

      @Override
      public void writeParams(TLOutputStream ostream) throws Exception {
        flags = icon_color != null ? (flags | 1) : (flags & ~1);
        flags = icon_emoji_id != null ? (flags | 8) : (flags & ~8);
        flags = send_as != null ? (flags | 4) : (flags & ~4);
        ostream.writeInt32(flags);
        channel.write(ostream);
        ostream.writeTLString(title);
        if ((flags & 1) != 0) {
          ostream.writeInt32(icon_color);
        }
        if ((flags & 8) != 0) {
          ostream.writeInt64(icon_emoji_id);
        }
        ostream.writeInt64(random_id);
        if ((flags & 4) != 0) {
          send_as.write(ostream);
        }

      }


      @Override
      public JsonObject toJSON() {
        Map<String, Object> _json = new LinkedHashMap<>();
        _json.put("@id", getId());
        _json.put("@name", getName());
        _json.put("@return_type", RETURN_TYPE);
        _json.put("flags", flags);
        _json.put("channel", channel.toJSON());
        _json.put("title", title);
        _json.put("icon_color", icon_color);
        _json.put("icon_emoji_id", icon_emoji_id);
        _json.put("random_id", random_id);
        _json.put("send_as", send_as != null ? send_as.toJSON() : null);

        return GSON.toJsonTree(_json).getAsJsonObject();
      }

